@@ -960,6 +960,91 @@
 export function drawCharactersSorted(characters: Character[], ctx: CanvasRenderingContext2D) {
   // Sort ascending by y (lower y first, higher y last)
   const sorted = characters.slice().sort((a, b) => a.y - b.y);
   for (const character of sorted) {
     drawCharacter(character, ctx, character.x, character.y);
   }
 }
+
+// Draw a dark archway doorway between rooms
+export function drawDoorway(ctx: CanvasRenderingContext2D, x: number, y: number, width: number, height: number) {
+  ctx.save();
+  ctx.fillStyle = '#222';
+  ctx.strokeStyle = '#111';
+  ctx.lineWidth = 2;
+  // Draw arch shape: a rectangle base with a semicircle top
+  ctx.beginPath();
+  ctx.moveTo(x, y + height);
+  ctx.lineTo(x, y + height / 2);
+  ctx.arc(x + width / 2, y + height / 2, width / 2, Math.PI, 0, false);
+  ctx.lineTo(x + width, y + height);
+  ctx.closePath();
+  ctx.fill();
+  ctx.stroke();
+  ctx.restore();
+}
+
+// Draw a corridor connecting two adjacent rooms
+// fromRoom and toRoom have {x, y, width, height} properties
+export function drawCorridor(ctx: CanvasRenderingContext2D, fromRoom: {x:number,y:number,width:number,height:number}, toRoom: {x:number,y:number,width:number,height:number}) {
+  ctx.save();
+  ctx.strokeStyle = '#333';
+  ctx.lineWidth = 8;
+  ctx.lineCap = 'round';
+  ctx.shadowColor = 'rgba(0,0,0,0.5)';
+  ctx.shadowBlur = 4;
+
+  // Compute center points of each room
+  const fromCenterX = fromRoom.x + fromRoom.width / 2;
+  const fromCenterY = fromRoom.y + fromRoom.height / 2;
+  const toCenterX = toRoom.x + toRoom.width / 2;
+  const toCenterY = toRoom.y + toRoom.height / 2;
+
+  ctx.beginPath();
+  ctx.moveTo(fromCenterX, fromCenterY);
+  ctx.lineTo(toCenterX, toCenterY);
+  ctx.stroke();
+  ctx.restore();
+}
+
+// Fade-in effect for drawing a room over 5 frames
+// drawRoomFunc is a function(ctx, room) that draws the room normally
+// room is the room object to draw
+// frame is the current fade frame 0..4
+export function drawRoomFadeIn(ctx: CanvasRenderingContext2D, room: any, drawRoomFunc: (ctx: CanvasRenderingContext2D, room: any) => void, frame: number) {
+  const maxFrames = 5;
+  const alpha = (frame + 1) / maxFrames;
+  ctx.save();
+  ctx.globalAlpha = alpha;
+  drawRoomFunc(ctx, room);
+  ctx.restore();
+}
+
+// Patch drawRoom to add fade-in effect and draw doorways and corridors
+// Assuming drawRoom is defined near line 966
+// We'll wrap the original drawRoom in a new function that supports fade-in and draws doorways/corridors
+import { rooms, adjacentRooms } from './room-data'; // hypothetical import for rooms and adjacency - escalate if missing
+
+let fadeFrame = 0;
+const maxFadeFrames = 5;
+
+const originalDrawRoom = drawRoom;
+
+export function drawRoom(ctx: CanvasRenderingContext2D, room: any) {
+  // Draw fade-in effect
+  drawRoomFadeIn(ctx, room, originalDrawRoom, fadeFrame);
+
+  // Draw doorways for each connected room
+  if (room.connectedRooms) {
+    for (const connectedRoom of room.connectedRooms) {
+      // Compute doorway position between rooms (simple midpoint of adjacent edges)
+      // For simplicity, assume rooms are axis-aligned rectangles
+      const doorWidth = 24;
+      const doorHeight = 40;
+      let doorX = 0;
+      let doorY = 0;
+
+      // Determine relative position of connectedRoom to room
+      if (connectedRoom.x > room.x + room.width) {
+        // connectedRoom is to the right
+        doorX = room.x + room.width - doorWidth / 2;
+        doorY = room.y + room.height / 2 - doorHeight / 2;
+      } else if (connectedRoom.x + connectedRoom.width < room.x) {
+        // connectedRoom is to the left
+        doorX = room.x - doorWidth / 2;
+        doorY = room.y + room.height / 2 - doorHeight / 2;
+      } else if (connectedRoom.y > room.y + room.height) {
+        // connectedRoom is below
+        doorX = room.x + room.width / 2 - doorWidth / 2;
+        doorY = room.y + room.height - doorHeight / 2;
+      } else if (connectedRoom.y + connectedRoom.height < room.y) {
+        // connectedRoom is above
+        doorX = room.x + room.width / 2 - doorWidth / 2;
+        doorY = room.y - doorHeight / 2;
+      }
+      drawDoorway(ctx, doorX, doorY, doorWidth, doorHeight);
+    }
+  }
+
+  // Draw corridors to adjacent rooms
+  if (room.connectedRooms) {
+    for (const connectedRoom of room.connectedRooms) {
+      drawCorridor(ctx, room, connectedRoom);
+    }
+  }
+
+  // Increment fade frame for next redraw
+  fadeFrame = (fadeFrame + 1) % maxFadeFrames;
+}
